{"domain_id":[1]}
{ "index" : { "_index" : "test", "_type": "arrays", "_id": 6}}
{"domain_id":[1]}
{ "index" : { "_index" : "test", "_type": "arrays", "_id": 7}}
{"domain_id":[1,8]}
{ "index" : { "_index" : "test", "_type": "arrays", "_id": 8}}
{"domain_id":[1]}
{ "index" : { "_index" : "test", "_type": "arrays", "_id": 9}}
{"domain_id":[1]}
